#include <iostream>
#include <set>

using namespace std;

int main()
{
    set<int> numbers;
    numbers.insert(30);
    numbers.insert(10);
    numbers.insert(20);
    numbers.insert(10); // duplicate — silently has no effect

    for (int n : numbers)
    {
        cout << n << " ";
    }

    return 0;
}

set<int> numbers = {10, 20, 30};

auto it = numbers.find(20);
if (it != numbers.end())
{
    cout << "Found!";
}

cout << numbers.count(20); // 1 — present
cout << numbers.count(99); // 0 — absent

